const shape = new THREE.Shape()
shape.moveTo(0, 0)
shape.lineTo(widthMm * mm, 0)
shape.lineTo(0, heightMm * mm)
shape.closePath()
const geo = new THREE.ExtrudeGeometry(shape, { depth: thicknessMm * mm, bevelEnabled: false })
const mat = new THREE.MeshLambertMaterial({ color: '#C8B89A' })
const mesh = new THREE.Mesh(geo, mat)
const group = new THREE.Group()
group.add(mesh)
return group
